function scrollToBottom(){window.scrollTo(0,document.body.scrollHeight);document.documentElement.scrollTop=document.documentElement.scrollHeight;if(window.parent&&window.parent!==window){try{window.parent.document.getElementById('log-container').scrollTop=window.parent.document.getElementById('log-container').scrollHeight}catch(e){}}}window.onload=scrollToBottom;setTimeout(scrollToBottom,100);